--
-- TOC entry 360 (class 1259 OID 28461)
-- Name: vista_cxc_con_vencimiento; Type: VIEW; Schema: public; Owner: ferram
--

CREATE VIEW public.vista_cxc_con_vencimiento AS
 SELECT p.pedidoid,
    p.clienteid,
    p.tenant_id,
    (((c.nombre)::text || ' '::text) || (c.apellido)::text) AS cliente_nombre,
    c.email AS cliente_email,
    p.fechapedido,
    p.fecha_vencimiento,
    p.montototal,
    COALESCE(p.saldo_pendiente, p.montototal) AS saldo_pendiente,
    p.estatus_deuda,
        CASE
            WHEN (p.fecha_vencimiento IS NULL) THEN 0
            WHEN ((p.fecha_vencimiento)::date > CURRENT_DATE) THEN 0
            ELSE (CURRENT_DATE - (p.fecha_vencimiento)::date)
        END AS dias_atraso_real,
    cc.dias_gracia AS dias_credito_cliente,
        CASE
            WHEN (p.fecha_vencimiento IS NULL) THEN 'Sin vencimiento'::text
            WHEN ((p.fecha_vencimiento)::date >= CURRENT_DATE) THEN 'Al corriente'::text
            WHEN ((CURRENT_DATE - (p.fecha_vencimiento)::date) <= 30) THEN 'Vencido 1-30 días'::text
            WHEN ((CURRENT_DATE - (p.fecha_vencimiento)::date) <= 60) THEN 'Vencido 31-60 días'::text
            WHEN ((CURRENT_DATE - (p.fecha_vencimiento)::date) <= 90) THEN 'Vencido 61-90 días'::text
            ELSE 'Vencido +90 días'::text
        END AS categoria_aging
   FROM ((public.pedidos p
     JOIN public.clientes c ON (((c.clienteid = p.clienteid) AND (c.tenant_id = p.tenant_id))))
     LEFT JOIN public.cliente_creditos cc ON (((cc.cliente_id = p.clienteid) AND (cc.tenant_id = p.tenant_id))))
  WHERE ((p.es_credito = true) AND (p.pagado = false) AND (COALESCE(p.saldo_pendiente, p.montototal) > (0)::numeric) AND ((p.estatus)::text <> ALL ((ARRAY['Cancelado'::character varying, 'Rechazado'::character varying])::text[])));


ALTER VIEW public.vista_cxc_con_vencimiento OWNER TO ferram;

--
-- TOC entry 5898 (class 0 OID 0)
-- Dependencies: 360
-- Name: VIEW vista_cxc_con_vencimiento; Type: COMMENT; Schema: public; Owner: ferram
--

COMMENT ON VIEW public.vista_cxc_con_vencimiento IS 'Cuentas por cobrar con análisis de vencimiento y aging, aislado por tenant';


--
-- TOC entry 366 (class 1259 OID 28694)
-- Name: vista_stock_con_reservas; Type: VIEW; Schema: public; Owner: ferram
--

CREATE VIEW public.vista_stock_con_reservas AS
 SELECT sa.stockadminid,
    sa.admin_id,
    COALESCE((((a.nombre)::text || ' '::text) || (a.apellido)::text), ('Admin ID '::text || sa.admin_id)) AS admin_nombre,
    sa.variante_id,
    pv.sku,
    p.nombreproducto,
    sa.cantidad AS stock_fisico,
    sa.cantidad_reservada AS stock_reservado,
    (sa.cantidad - sa.cantidad_reservada) AS stock_disponible,
    round((((sa.cantidad_reservada)::numeric / (NULLIF(sa.cantidad, 0))::numeric) * (100)::numeric), 2) AS porcentaje_reservado,
    sa.tenant_id,
    sa.updated_at
   FROM (((public.stock_admin sa
     LEFT JOIN public.producto_variantes pv ON ((pv.varianteid = sa.variante_id)))
     LEFT JOIN public.productos p ON (((p.productoid = pv.productoid) AND (p.tenant_id = sa.tenant_id))))
     LEFT JOIN public.administradores a ON (((a.adminid = sa.admin_id) AND (a.tenant_id = sa.tenant_id))))
  WHERE (sa.cantidad > 0)
  ORDER BY sa.cantidad_reservada DESC, sa.tenant_id, sa.admin_id;


ALTER VIEW public.vista_stock_con_reservas OWNER TO ferram;

